from re import sub
from unicodedata import normalize

def slugify(title: str) -> str:
    title = normalize('NFKD', title).encode('ASCII', 'ignore').decode().lower()
    title = sub(r'[^a-z0-9]+', '-', title)
    return title.strip('-')

import re
import unicodedata

def slugify(title: str) -> str:
    title = unicodedata.normalize('NFKCD', title)
    title = re.sub(r'[\s\W]+', '-', title).lower()
    return title.strip('-')
